// @namespace    http://tampermonkey.net/
// @version      1.8
// @description  Bookmark, filter and export your Tomorrowland timetable as a high-resolution PNG/PDF (incl. iPhone lock-screen)
// @author       Antigravity
// @match        https://belgium.tomorrowland.com/*
// @grant         none
// @run-at       document-end
