    // Show a micro-toast notification
    function showToast(message) {
        let toast = document.getElementById('tml-filter-toast');
        if (!toast) {
            toast = document.createElement('div');
            toast.id = 'tml-filter-toast';
            toast.className = 'tml-toast';
            document.body.appendChild(toast);
        }
        toast.textContent = message;
        toast.className = 'tml-toast tml-show';
        setTimeout(() => {
            toast.className = 'tml-toast';
        }, 2500);
    }

    // Toggle the selected state of an act
    function toggleAct(id, programEl, bookmarkBtn) {
        if (selectedIds.has(id)) {
            selectedIds.delete(id);
            programEl.classList.remove('tml-selected');
            bookmarkBtn.classList.remove('tml-active');
        } else {
            selectedIds.add(id);
            programEl.classList.add('tml-selected');
            bookmarkBtn.classList.add('tml-active');
        }
        
        saveState();
        updatePanelUI();
        applyFilterClasses();
    }

    // Update the numbers and states in the control panel UI
    function updatePanelUI() {
        const countLabel = document.getElementById('tml-selected-count');
        if (countLabel) {
            countLabel.textContent = selectedIds.size;
        }

        const toggleHideCheckbox = document.getElementById('tml-toggle-hide');
        if (toggleHideCheckbox) {
            toggleHideCheckbox.checked = hideUnselected;
        }

        const modeGroup = document.getElementById('tml-mode-group');
        if (modeGroup) {
            modeGroup.style.display = hideUnselected ? 'block' : 'none';
        }

        const radioFade = document.querySelector('input[name="tml-hide-mode"][value="fade"]');
        const radioHide = document.querySelector('input[name="tml-hide-mode"][value="hide"]');
        if (radioFade && radioHide) {
            radioFade.checked = fadeMode;
            radioHide.checked = !fadeMode;
        }
    }

    // Apply filtering classes to the `.planby` wrapper in the target DOM space
    function applyFilterClasses() {
        const root = getLineupRoot();
        const planbyContainer = root.querySelector('.planby, [class*="planby"]');
        if (!planbyContainer) return;

        if (hideUnselected) {
            planbyContainer.classList.add('tml-hide-unselected');
            if (!fadeMode) {
                planbyContainer.classList.add('tml-mode-hide');
            } else {
                planbyContainer.classList.remove('tml-mode-hide');
            }
        } else {
            planbyContainer.classList.remove('tml-hide-unselected');
            planbyContainer.classList.remove('tml-mode-hide');
        }
    }

    // Reset all selections
    function resetSelections() {
        if (selectedIds.size === 0) return;
        if (!confirm('Are you sure you want to clear your selected acts?')) return;
        
        selectedIds.clear();
        saveState();

        const root = getLineupRoot();
        root.querySelectorAll('[class*="e1ojkxpe1"], [class*="_program_"], .planby-program').forEach(el => el.classList.remove('tml-selected'));
        root.querySelectorAll('.tml-bookmark-btn').forEach(el => el.classList.remove('tml-active'));

        updatePanelUI();
        applyFilterClasses();
        showToast('Selections cleared');
    }

    // ============================================================
    //  Schedule Export (PNG / PDF) — clean rebuilt timetable
    // ============================================================

    function esc(s) {
        return String(s == null ? '' : s).replace(/[&<>"]/g, c => (
            { '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;' }[c]
        ));
    }

    function startLabelOf(a) {
        return a.startLabel || (a.startMs != null ? fmtTime(new Date(a.startMs)) : '--:--');
    }
    function endLabelOf(a) {
        return a.endLabel || (a.endMs != null ? fmtTime(new Date(a.endMs)) : '--:--');
    }

    // Human-readable label for the day currently shown (from the ?day= query param).
    function getDayLabel() {
        const day = new URLSearchParams(location.search).get('day');
        if (!day) return '';
        const d = new Date(day + 'T00:00:00');
        if (isNaN(d)) return day;
        return d.toLocaleDateString(undefined, { weekday: 'long', day: 'numeric', month: 'long' });
    }

    // Position of an act on a continuous minute axis (festival nights roll past midnight).
    function actMinutes(a) {
        const toMin = (ms, label) => {
            if (ms != null) {
                const d = new Date(ms);
                let h = d.getHours();
                if (h < 6) h += 24;
                return h * 60 + d.getMinutes();
            }
            if (label) {
                const parts = label.split(':');
                let h = parseInt(parts[0], 10);
                const m = parseInt(parts[1], 10);
                if (isNaN(h) || isNaN(m)) return null;
                if (h < 6) h += 24;
                return h * 60 + m;
            }
            return null;
        };
        const s = toMin(a.startMs, a.startLabel);
        if (s == null) return null;
        let e = toMin(a.endMs, a.endLabel);
        if (e == null) e = s + 60;
        if (e <= s) e += 24 * 60;
        return { s, e };
    }

    // The festival day an act belongs to (the calendar date after shifting back 6h, so a 01:00 set
    // still counts as the previous evening's lineup).
    function festivalDayOf(act) {
        if (act.startMs == null) return null;
        const d = new Date(act.startMs - 6 * 3600 * 1000);
        return d.getFullYear() + '-' + String(d.getMonth() + 1).padStart(2, '0') + '-' + String(d.getDate()).padStart(2, '0');
    }
    function actMatchesDay(act, day) {
        if (act.day) return act.day === day;        // captured under this day's view
        const fd = festivalDayOf(act);
        if (fd) return fd === day;                  // derived from the start time
        return true;                                // undeterminable → keep
    }

    // Collect the selected acts for the currently-viewed day from the cache, sorted chronologically.
    function buildScheduleData() {
        const currentDay = new URLSearchParams(location.search).get('day');
        const acts = [];
        let missing = 0;
        selectedIds.forEach(id => {
            const d = actData[id];
            const act = (d && d.name)
                ? Object.assign({ id }, d)
                : { id, name: 'Unknown act', stage: '', startMs: null, endMs: null, startLabel: '', endLabel: '' };
            if (currentDay && !actMatchesDay(act, currentDay)) return;
            if (!(d && d.name)) missing++;
            acts.push(act);
        });
        const sortKey = a => {
            const m = actMinutes(a);
            return m ? m.s : Number.MAX_SAFE_INTEGER;
        };
        acts.sort((a, b) => sortKey(a) - sortKey(b));
        return { acts, missing };
    }

    // Distinct colours per stage, readable on the dark background.
    const STAGE_PALETTE = [
        '#d4af37', '#5bc0eb', '#e0566b', '#00f5d4', '#9b5de5', '#ff8c42',
        '#f15bb5', '#8ac926', '#4cc9f0', '#ffd166', '#06d6a0', '#b5179e',
        '#ff5d8f', '#fee440', '#00bbf9', '#c1ff72'
    ];
    function hexToRgba(hex, a) {
        const h = hex.replace('#', '');
        const r = parseInt(h.slice(0, 2), 16);
        const g = parseInt(h.slice(2, 4), 16);
        const b = parseInt(h.slice(4, 6), 16);
        return `rgba(${r},${g},${b},${a})`;
    }
    // Stable stage→colour map: assigns palette colours in the given stage order.
    function buildStageColors(order) {
        const m = {};
        order.forEach((st, i) => { m[st] = STAGE_PALETTE[i % STAGE_PALETTE.length]; });
        return m;
    }
    // Neon edge glow for a given colour, as an inline text-shadow value (subtle).
    function glow(c) {
        return `text-shadow:0 0 3px ${hexToRgba(c, 0.85)},0 0 8px ${hexToRgba(c, 0.4)}`;
    }

    const EXPORT_FONT_STACK = '-apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif';
    const _measureCtx = document.createElement('canvas').getContext('2d');
    // Largest font size (<= basePx) at which the text fits maxWidthPx. By default only the widest
    // single word must fit (multi-word names still wrap); whole:true requires the entire string.
    function fitFontPx(text, maxWidthPx, basePx, options) {
        options = options || {};
        const weight = options.weight || 700;
        const minPx = options.min || 9;
        if (!text || maxWidthPx <= 0) return basePx;
        _measureCtx.font = weight + ' ' + basePx + 'px ' + EXPORT_FONT_STACK;
        let widest = 0;
        if (options.whole) {
            widest = _measureCtx.measureText(String(text)).width;
        } else {
            String(text).split(/\s+/).forEach(w => {
                const ww = _measureCtx.measureText(w).width;
                if (ww > widest) widest = ww;
            });
        }
        if (widest <= maxWidthPx) return basePx;
        return Math.max(minPx, Math.floor(basePx * maxWidthPx / widest));
    }
    // Number of lines the greedily-wrapped text occupies at the current _measureCtx font.
    function wrapLineCount(words, maxW) {
        let lines = 1, cur = 0;
        words.forEach(w => {
            const ww = _measureCtx.measureText(w + ' ').width;
            if (cur > 0 && cur + ww > maxW) { lines++; cur = ww; }
            else cur += ww;
        });
        return lines;
    }
    // Largest font size (<= basePx) at which the text fits BOTH the box width and height (after
    // wrapping). Used so names don't get clipped at the bottom of short boxes.
    function fitFontBox(text, boxW, boxH, basePx, lineHeight, options) {
        options = options || {};
        const weight = options.weight || 700;
        const minPx = options.min || 8;
        if (!text || boxW <= 0 || boxH <= 0) return basePx;
        const words = String(text).split(/\s+/);
        for (let size = basePx; size >= minPx; size--) {
            _measureCtx.font = weight + ' ' + size + 'px ' + EXPORT_FONT_STACK;
            let widest = 0;
            words.forEach(w => { const ww = _measureCtx.measureText(w).width; if (ww > widest) widest = ww; });
            if (widest > boxW) continue;
            if (wrapLineCount(words, boxW) * size * lineHeight <= boxH) return size;
        }
        return minPx;
    }
    // Unique stages in first-seen order across a list of acts.
    function stagesInOrder(acts) {
        const seen = new Set();
        const order = [];
        acts.forEach(a => {
            const st = a.stage || 'Other';
            if (!seen.has(st)) { seen.add(st); order.push(st); }
        });
        return order;
    }

    // Shared stylesheet for the rendered (rasterized) schedule. Uses system fonts so it
    // renders identically inside the SVG/canvas pipeline without loading web fonts.
    function exportStyleBlock() {
        return `<style>
            .tmlx-root {
                box-sizing: border-box;
                font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
                background: #0e0e12;
                color: #ffffff;
                padding: 24px;
            }
            .tmlx-root * { box-sizing: border-box; }
            .tmlx-vertical { width: 460px; }
            .tmlx-fill { display: flex; flex-direction: column; }
            .tmlx-fill .tmlx-list { flex: 1 1 auto; justify-content: space-between; }
            .tmlx-header { text-align: center; margin-bottom: 20px; padding-bottom: 16px; border-bottom: 1px solid rgba(212,175,55,0.35); }
            .tmlx-brand { font-size: 13px; font-weight: 800; letter-spacing: 3px; color: #d4af37; }
            .tmlx-day { font-size: 22px; font-weight: 800; margin-top: 6px; color: #ffffff; }
            .tmlx-count { font-size: 12px; color: rgba(255,255,255,0.55); margin-top: 4px; }
            .tmlx-list { display: flex; flex-direction: column; gap: 10px; }
            .tmlx-card { display: flex; align-items: stretch; gap: 14px; background: rgba(255,255,255,0.04); border: 1px solid rgba(212,175,55,0.25); border-radius: 10px; padding: 12px 14px; }
            .tmlx-time { display: flex; flex-direction: column; justify-content: center; align-items: center; min-width: 58px; padding-right: 12px; border-right: 1px solid rgba(212,175,55,0.25); }
            .tmlx-tstart { font-size: 17px; font-weight: 800; color: #d4af37; }
            .tmlx-tend { font-size: 12px; color: rgba(255,255,255,0.45); margin-top: 2px; }
            .tmlx-info { display: flex; flex-direction: column; justify-content: center; }
            .tmlx-name { font-size: 17px; font-weight: 700; line-height: 1.2; }
            .tmlx-stage { font-size: 12px; font-weight: 600; letter-spacing: 0.5px; color: #d4af37; margin-top: 4px; text-transform: uppercase; }
            .tmlx-footer { text-align: center; font-size: 10px; letter-spacing: 1px; color: rgba(255,255,255,0.3); margin-top: 18px; }
            .tmlx-hheader { display: flex; align-items: baseline; gap: 14px; margin-bottom: 16px; }
            .tmlx-hheader .tmlx-day { font-size: 20px; margin-top: 0; }
            .tmlx-grid { position: relative; }
            .tmlx-srow { position: absolute; left: 0; right: 0; background: rgba(255,255,255,0.03); border-top: 1px solid rgba(255,255,255,0.06); }
            .tmlx-slabel { position: absolute; left: 0; width: 150px; display: flex; align-items: center; padding: 0 12px; font-size: 13px; font-weight: 700; color: #d4af37; text-transform: uppercase; letter-spacing: 0.5px; z-index: 3; }
            .tmlx-gridline { position: absolute; top: 0; bottom: 0; width: 1px; background: rgba(255,255,255,0.07); }
            .tmlx-tick { position: absolute; top: 0; height: 40px; display: flex; align-items: center; transform: translateX(4px); font-size: 11px; color: rgba(255,255,255,0.5); z-index: 2; }
            .tmlx-block { position: absolute; background: rgba(212,175,55,0.16); border: 1px solid #d4af37; border-radius: 6px; padding: 6px 8px; overflow: hidden; z-index: 4; }
            .tmlx-bname { font-size: 13px; font-weight: 700; line-height: 1.15; overflow: hidden; display: -webkit-box; -webkit-line-clamp: 2; -webkit-box-orient: vertical; }
            .tmlx-btime { font-size: 10px; color: #d4af37; margin-top: 3px; }

            /* Vertical stage-columns layout: stages across, time down */
            .tmlx-header-left { text-align: left; }
            .tmlx-vgrid { position: relative; }
            .tmlx-vsep { position: absolute; top: 0; width: 1px; background: rgba(255,255,255,0.08); z-index: 1; }
            .tmlx-vhead { position: absolute; top: 0; height: 46px; display: flex; align-items: center; justify-content: center; text-align: center; padding: 0 8px; font-size: 13px; font-weight: 800; letter-spacing: 0.5px; color: #d4af37; text-transform: uppercase; line-height: 1.1; z-index: 3; }
            .tmlx-vline { position: absolute; right: 0; height: 1px; background: rgba(255,255,255,0.07); z-index: 1; }
            .tmlx-vtime { position: absolute; left: 0; width: 46px; text-align: right; padding-right: 8px; transform: translateY(-50%); font-size: 11px; color: rgba(255,255,255,0.5); z-index: 2; }
            .tmlx-vblock { position: absolute; display: flex; flex-direction: column; background: rgba(212,175,55,0.16); border: 1px solid #d4af37; border-radius: 8px; padding: 7px 9px; overflow: hidden; z-index: 4; }
            .tmlx-vbtime { font-size: 11px; font-weight: 600; color: #d4af37; }
            .tmlx-vbname { font-size: 14px; font-weight: 700; line-height: 1.18; margin-top: 3px; overflow: hidden; display: -webkit-box; -webkit-line-clamp: 8; -webkit-box-orient: vertical; }

            /* Bigger, bolder sizing for fixed-size (phone / lock-screen) exports */
            .tmlx-big { background: transparent; }
            .tmlx-big .tmlx-card { background: rgba(0,0,0,0.30); }
            .tmlx-big .tmlx-header { text-align: center; margin-bottom: 30px; padding-bottom: 24px; }
            .tmlx-big .tmlx-brand { font-size: 32px; letter-spacing: 6px; text-shadow: 0 0 6px rgba(212,175,55,0.5); }
            .tmlx-big .tmlx-day { font-size: 64px; margin-top: 12px; line-height: 1.05; text-shadow: 0 0 7px rgba(255,255,255,0.32); }
            .tmlx-big .tmlx-count { font-size: 26px; margin-top: 14px; }
            .tmlx-big .tmlx-card { padding: 22px 24px; gap: 20px; border-left-width: 6px; }
            .tmlx-big .tmlx-time { min-width: 162px; padding-right: 22px; }
            .tmlx-big .tmlx-tstart { font-size: 50px; }
            .tmlx-big .tmlx-tend { font-size: 26px; margin-top: 4px; }
            .tmlx-big .tmlx-name { font-size: 50px; line-height: 1.1; }
            .tmlx-big .tmlx-stage { font-size: 26px; margin-top: 8px; }
            .tmlx-big .tmlx-vhead { font-size: 32px; }
            .tmlx-big .tmlx-vblock { padding: 14px 16px; border-radius: 12px; }
            .tmlx-big .tmlx-vbtime { font-size: 26px; }
            .tmlx-big .tmlx-vbname { font-size: 40px; line-height: 1.12; margin-top: 8px; -webkit-line-clamp: 8; }
            .tmlx-big .tmlx-vtime { font-size: 26px; width: 88px; padding-right: 12px; }
            .tmlx-big .tmlx-footer { font-size: 22px; margin-top: 26px; }

            /* Compact header (iOS 26 lock screen): no brand, smaller flatter day */
            .tmlx-compact .tmlx-brand { display: none; }
            .tmlx-compact .tmlx-header { margin-bottom: 18px; padding-bottom: 14px; }
            .tmlx-compact .tmlx-day { font-size: 32px; font-weight: 500; letter-spacing: 1px; line-height: 1.1; text-shadow: 0 0 5px rgba(255,255,255,0.25); }
        </style>`;
    }

    // Vertical phone-friendly agenda: time runs top to bottom.
    // opts (optional) = { w, h }: target screen ratio — the card list stretches to fill the height.
    function renderVertical(acts, opts) {
        const big = !!opts;
        const colors = buildStageColors(stagesInOrder(acts));
        const nameBase = big ? 50 : 17;
        // Available width inside the info column (mirrors the .tmlx-card CSS metrics).
        const cardInnerW = (460 - 48) - (big ? 48 : 28);
        const timeColW = (big ? 162 : 58) + (big ? 22 : 12) + 1;
        const nameMaxW = cardInnerW - timeColW - (big ? 20 : 14);
        const rows = acts.map(a => {
            const c = colors[a.stage || 'Other'] || STAGE_PALETTE[0];
            const nameSize = fitFontPx(a.name, nameMaxW, nameBase);
            return `
            <div class="tmlx-card" style="border-left:4px solid ${c}">
                <div class="tmlx-time">
                    <div class="tmlx-tstart" style="color:${c};${glow(c)}">${esc(startLabelOf(a))}</div>
                    <div class="tmlx-tend">${esc(endLabelOf(a))}</div>
                </div>
                <div class="tmlx-info">
                    <div class="tmlx-name" style="font-size:${nameSize}px;${glow(c)}">${esc(a.name)}</div>
                    ${a.stage ? `<div class="tmlx-stage" style="color:${c};${glow(c)}">${esc(a.stage)}</div>` : ''}
                </div>
            </div>`;
        }).join('');
        const wrap = document.createElement('div');
        wrap.className = 'tmlx-root tmlx-vertical';
        if (opts) {
            // Keep the natural design width; match the chosen screen aspect by computing height,
            // then distribute the cards to fill it (handled by .tmlx-fill CSS).
            const designW = 460;
            wrap.classList.add('tmlx-fill', 'tmlx-big');
            if (opts.compact) wrap.classList.add('tmlx-compact');
            wrap.style.width = designW + 'px';
            // min-height (not height) so the list fills a short schedule but grows for a long one.
            wrap.style.minHeight = Math.round(designW * opts.h / opts.w) + 'px';
        }
        wrap.innerHTML = exportStyleBlock() + `
            <div class="tmlx-header">
                <div class="tmlx-brand">TOMORROWLAND CONSCIENCIA</div>
                <div class="tmlx-day">${esc(getDayLabel())}</div>
            </div>
            <div class="tmlx-list">${rows}</div>`;
        return wrap;
    }

    // Horizontal grid: stages as rows, time runs left to right.
    function renderHorizontal(acts) {
        const placed = acts.map(a => ({ a, m: actMinutes(a) })).filter(x => x.m);
        if (placed.length === 0) return renderVertical(acts);

        let min = Math.min.apply(null, placed.map(x => x.m.s));
        let max = Math.max.apply(null, placed.map(x => x.m.e));
        min = Math.floor(min / 60) * 60;
        max = Math.ceil(max / 60) * 60;

        const pxPerMin = 3;
        const labelW = 150;
        const rowH = 64;
        const headH = 40;
        const axisW = (max - min) * pxPerMin;

        const stageFirst = {};
        const stageOrder = [];
        placed.forEach(x => {
            const st = x.a.stage || 'Unknown stage';
            if (!(st in stageFirst)) { stageFirst[st] = x.m.s; stageOrder.push(st); }
            else stageFirst[st] = Math.min(stageFirst[st], x.m.s);
        });
        stageOrder.sort((p, q) => stageFirst[p] - stageFirst[q]);
        const stageIndex = {};
        stageOrder.forEach((st, i) => { stageIndex[st] = i; });
        const colors = buildStageColors(stageOrder);

        let ticks = '';
        for (let t = min; t <= max; t += 60) {
            const left = labelW + (t - min) * pxPerMin;
            const hr = (Math.floor(t / 60)) % 24;
            ticks += `<div class="tmlx-gridline" style="left:${left}px"></div>`;
            ticks += `<div class="tmlx-tick" style="left:${left}px">${String(hr).padStart(2, '0')}:00</div>`;
        }

        let stageLabels = '';
        stageOrder.forEach((st, i) => {
            const top = headH + i * rowH;
            const sSize = fitFontPx(st, labelW - 24, 13);
            stageLabels += `<div class="tmlx-srow" style="top:${top}px;height:${rowH}px"></div>`;
            stageLabels += `<div class="tmlx-slabel" style="top:${top}px;height:${rowH}px;color:${colors[st]};font-size:${sSize}px;${glow(colors[st])}">${esc(st)}</div>`;
        });

        let blocks = '';
        placed.forEach(x => {
            const st = x.a.stage || 'Unknown stage';
            const i = stageIndex[st];
            const c = colors[st];
            const left = labelW + (x.m.s - min) * pxPerMin + 2;
            const width = Math.max(44, (x.m.e - x.m.s) * pxPerMin - 4);
            const top = headH + i * rowH + 6;
            const innerW = width - 16 - 4;               // padding + 4px safety
            const timeStr = startLabelOf(x.a) + '–' + endLabelOf(x.a);
            const tSize = fitFontPx(timeStr, innerW, 10, { whole: true, weight: 600, min: 6 });
            const nameBoxH = (rowH - 12) - 12 - (tSize * 1.2 + 2);
            const nSize = fitFontBox(x.a.name, innerW, nameBoxH, 13, 1.15, { min: 6 });
            blocks += `<div class="tmlx-block" style="left:${left}px;width:${width}px;top:${top}px;height:${rowH - 12}px;background:${hexToRgba(c, 0.16)};border-color:${c}">
                <div class="tmlx-bname" style="font-size:${nSize}px;${glow(c)}">${esc(x.a.name)}</div>
                <div class="tmlx-btime" style="font-size:${tSize}px;color:${c};${glow(c)}">${esc(timeStr)}</div>
            </div>`;
        });

        const totalW = labelW + axisW + 24;
        const totalH = headH + stageOrder.length * rowH + 8;
        const wrap = document.createElement('div');
        wrap.className = 'tmlx-root tmlx-horizontal';
        wrap.style.width = totalW + 'px';
        wrap.innerHTML = exportStyleBlock() + `
            <div class="tmlx-hheader">
                <span class="tmlx-brand">TOMORROWLAND CONSCIENCIA</span>
                <span class="tmlx-day">${esc(getDayLabel())}</span>
            </div>
            <div class="tmlx-grid" style="width:${totalW}px;height:${totalH}px">
                ${stageLabels}${ticks}${blocks}
            </div>`;
        return wrap;
    }

    // Shared helpers for the timeline-based layouts.
    function computeStageColumns(placed) {
        const stageFirst = {};
        const order = [];
        placed.forEach(x => {
            const st = x.a.stage || 'Other';
            if (!(st in stageFirst)) { stageFirst[st] = x.m.s; order.push(st); }
            else stageFirst[st] = Math.min(stageFirst[st], x.m.s);
        });
        order.sort((p, q) => stageFirst[p] - stageFirst[q]);
        const index = {};
        order.forEach((st, i) => { index[st] = i; });
        return { order, index };
    }

    // Vertical timetable: each stage is a column, time runs top to bottom.
    // opts (optional) = { w, h }: target screen ratio — columns fill the width and the time axis
    // stretches to fill the height so the export uses the whole screen.
    function renderVerticalColumns(acts, opts) {
        const placed = acts.map(a => ({ a, m: actMinutes(a) })).filter(x => x.m);
        if (placed.length === 0) return renderVertical(acts, opts);

        let min = Math.min.apply(null, placed.map(x => x.m.s));
        let max = Math.max.apply(null, placed.map(x => x.m.e));
        min = Math.floor(min / 60) * 60;
        max = Math.ceil(max / 60) * 60;
        const totalMinutes = max - min;

        const rootPad = 24;                  // matches .tmlx-root padding
        const gutterW = opts ? 100 : 54;     // wider gutter for the larger time labels
        const headH = opts ? 72 : 46;        // taller header row for the larger stage names
        const { order, index } = computeStageColumns(placed);
        const colors = buildStageColors(order);

        let colW, pxPerMin;
        if (opts) {
            // Fill the chosen screen: columns span the width, time axis spans the height.
            const contentW = opts.w - 2 * rootPad;
            colW = Math.max(120, (contentW - gutterW) / order.length);
            const overhead = opts.compact ? 150 : 230;   // header + paddings above/below the grid
            const availBodyH = opts.h - overhead - headH;
            pxPerMin = Math.max(1.5, availBodyH / totalMinutes);
        } else {
            colW = 168;
            pxPerMin = 1.7;            // ~102px per hour
        }
        const bodyH = totalMinutes * pxPerMin;

        // Hour gridlines + time labels down the left gutter.
        let grid = '';
        for (let t = min; t <= max; t += 60) {
            const top = headH + (t - min) * pxPerMin;
            const hr = (Math.floor(t / 60)) % 24;
            grid += `<div class="tmlx-vline" style="top:${top}px;left:${gutterW}px"></div>`;
            grid += `<div class="tmlx-vtime" style="top:${top}px">${String(hr).padStart(2, '0')}:00</div>`;
        }

        const headBase = opts ? 32 : 13;
        const nameBase = opts ? 40 : 14;
        const blockPadX = opts ? 32 : 18;

        // Column headers (stage names) + faint column separators.
        let heads = '';
        order.forEach((st, i) => {
            const left = gutterW + i * colW;
            const hSize = fitFontPx(st, colW - 16, headBase);
            heads += `<div class="tmlx-vsep" style="left:${left}px;height:${headH + bodyH}px"></div>`;
            heads += `<div class="tmlx-vhead" style="left:${left}px;width:${colW}px;height:${headH}px;color:${colors[st]};font-size:${hSize}px;${glow(colors[st])}">${esc(st)}</div>`;
        });

        let blocks = '';
        placed.forEach(x => {
            const st = x.a.stage || 'Other';
            const i = index[st];
            const c = colors[st];
            const left = gutterW + i * colW + 5;
            const width = colW - 10;
            const top = headH + (x.m.s - min) * pxPerMin + 3;
            const height = Math.max(34, (x.m.e - x.m.s) * pxPerMin - 6);
            const padY = opts ? 14 : 7;
            const innerW = width - blockPadX - 4;        // 4px safety so nothing touches the edge
            // Time line: shrink so the whole "HH:mm – HH:mm" fits the column width (no right clip).
            const timeStr = startLabelOf(x.a) + ' – ' + endLabelOf(x.a);
            const tSize = fitFontPx(timeStr, innerW, opts ? 26 : 11, { whole: true, weight: 600, min: 7 });
            const nameMargin = opts ? 8 : 3;
            const timeH = tSize * 1.25 + nameMargin;
            // Name fits the remaining height (no bottom clip) and the width (no right clip).
            const nameBoxH = height - 2 * padY - timeH - 2;
            const nSize = fitFontBox(x.a.name, innerW, nameBoxH, nameBase, 1.16, { min: 7 });
            blocks += `<div class="tmlx-vblock" style="left:${left}px;width:${width}px;top:${top}px;height:${height}px;background:${hexToRgba(c, 0.16)};border-color:${c}">
                <div class="tmlx-vbtime" style="font-size:${tSize}px;color:${c};${glow(c)}">${esc(timeStr)}</div>
                <div class="tmlx-vbname" style="font-size:${nSize}px;${glow(c)}">${esc(x.a.name)}</div>
            </div>`;
        });

        const totalW = gutterW + order.length * colW;
        const totalH = headH + bodyH;
        const fullW = totalW + 2 * rootPad;
        const wrap = document.createElement('div');
        wrap.className = 'tmlx-root tmlx-vcols' + (opts ? ' tmlx-big' : '') + (opts && opts.compact ? ' tmlx-compact' : '');
        // Normally fill the target width; if many stages overflow it, widen so nothing is clipped.
        wrap.style.width = (opts ? Math.max(opts.w, fullW) : fullW) + 'px';
        wrap.innerHTML = exportStyleBlock() + `
            <div class="tmlx-header">
                <div class="tmlx-brand">TOMORROWLAND CONSCIENCIA</div>
                <div class="tmlx-day">${esc(getDayLabel())}</div>
            </div>
            <div class="tmlx-vgrid" style="width:${totalW}px;height:${totalH}px">
                ${heads}${grid}${blocks}
            </div>`;
        return wrap;
    }

    // Rasterize a DOM node to a canvas via an SVG <foreignObject> (no external libraries).
    // Browser canvas safety limits (Chrome caps a single dimension and total area).
    const MAX_CANVAS_DIM = 16000;
    const MAX_CANVAS_AREA = 250e6;

    function clampScale(w, h, scale) {
        let s = scale;
        if (w * s > MAX_CANVAS_DIM) s = MAX_CANVAS_DIM / w;
        if (h * s > MAX_CANVAS_DIM) s = Math.min(s, MAX_CANVAS_DIM / h);
        if (w * s * h * s > MAX_CANVAS_AREA) s = Math.sqrt(MAX_CANVAS_AREA / (w * h));
        return Math.max(1, s);
    }

    function elementToCanvas(node, scale, transparent) {
        const rect = node.getBoundingClientRect();
        const w = Math.max(1, Math.ceil(rect.width));
        const h = Math.max(1, Math.ceil(rect.height));
        const s = clampScale(w, h, scale || 4);
        node.setAttribute('xmlns', 'http://www.w3.org/1999/xhtml');
        const xml = new XMLSerializer().serializeToString(node);
        const svg =
            '<svg xmlns="http://www.w3.org/2000/svg" width="' + w + '" height="' + h + '">' +
            '<foreignObject x="0" y="0" width="' + w + '" height="' + h + '">' + xml + '</foreignObject></svg>';
        const url = 'data:image/svg+xml;charset=utf-8,' + encodeURIComponent(svg);
        return new Promise((resolve, reject) => {
            const img = new Image();
            img.onload = () => {
                const c = document.createElement('canvas');
                c.width = Math.round(w * s);
                c.height = Math.round(h * s);
                const ctx = c.getContext('2d');
                ctx.scale(s, s);
                if (!transparent) {
                    ctx.fillStyle = '#0e0e12';
                    ctx.fillRect(0, 0, w, h);
                }
                ctx.drawImage(img, 0, 0);
                resolve(c);
            };
            img.onerror = reject;
            img.src = url;
        });
    }

    // Load the inlined wallpaper image once (data URL → never taints the canvas).
    let wallpaperPromise = null;
    function loadWallpaper() {
        if (wallpaperPromise) return wallpaperPromise;
        wallpaperPromise = new Promise((resolve) => {
            if (typeof TML_WALLPAPER === 'undefined' || !TML_WALLPAPER) { resolve(null); return; }
            const img = new Image();
            img.onload = () => resolve(img);
            img.onerror = () => resolve(null);
            img.src = TML_WALLPAPER;
        });
        return wallpaperPromise;
    }

    // Load the inlined Consciencia logo once.
    let logoPromise = null;
    function loadLogo() {
        if (logoPromise) return logoPromise;
        logoPromise = new Promise((resolve) => {
            if (typeof TML_LOGO === 'undefined' || !TML_LOGO) { resolve(null); return; }
            const img = new Image();
            img.onload = () => resolve(img);
            img.onerror = () => resolve(null);
            img.src = TML_LOGO;
        });
        return logoPromise;
    }

    // Draw an image with its rectangular edges feathered to transparent so it blends into the
    // background instead of showing a hard border. fx/fy are the feather widths (px) on the
    // horizontal/vertical edges; opacity dims the whole image so it sits back into the background.
    function drawFeatheredImage(ctx, img, x, y, w, h, fx, fy, opacity) {
        const off = document.createElement('canvas');
        off.width = Math.round(w);
        off.height = Math.round(h);
        const o = off.getContext('2d');
        o.drawImage(img, 0, 0, off.width, off.height);
        o.globalCompositeOperation = 'destination-out';
        const cx = Math.max(1, Math.round(fx));
        const cy = Math.max(1, Math.round(fy));
        // A soft (eased) gradient gives a more gradual drop-off than a straight linear ramp.
        const ramp = (g) => { g.addColorStop(0, 'rgba(0,0,0,1)'); g.addColorStop(0.5, 'rgba(0,0,0,0.5)'); g.addColorStop(1, 'rgba(0,0,0,0)'); return g; };
        const edges = [
            [0, 0, cx, off.height, ramp(o.createLinearGradient(0, 0, cx, 0))],
            [off.width - cx, 0, cx, off.height, ramp(o.createLinearGradient(off.width, 0, off.width - cx, 0))],
            [0, 0, off.width, cy, ramp(o.createLinearGradient(0, 0, 0, cy))],
            [0, off.height - cy, off.width, cy, ramp(o.createLinearGradient(0, off.height, 0, off.height - cy))],
        ];
        edges.forEach(([rx, ry, rw, rh, g]) => { o.fillStyle = g; o.fillRect(rx, ry, rw, rh); });
        o.globalCompositeOperation = 'source-over';
        ctx.save();
        ctx.globalAlpha = opacity != null ? opacity : 1;
        ctx.drawImage(off, Math.round(x), Math.round(y));
        ctx.restore();
    }

    // Shared export geometry (device pixels) for a fixed-size preset.
    function exportGeometry(preset) {
        const finalW = Math.round(preset.w * PRESET_QUALITY);
        const finalH = Math.round(preset.h * PRESET_QUALITY);
        const sidePad = Math.round(finalW * 0.025);
        const topPad = Math.round(finalH * (preset.topInset != null ? preset.topInset : 0.025));
        const botReserve = Math.round(finalH * (preset.bottomInset != null ? preset.bottomInset : 0.03));
        const contentW = finalW - 2 * sidePad;
        const contentH = finalH - topPad - botReserve;
        return { finalW, finalH, sidePad, topPad, botReserve, contentW, contentH };
    }

    // Aspect-ratio presets (portrait), in native device pixels — already 4K-class.
    // topInset / bottomInset = fractions of height kept clear at the top (Dynamic Island / status bar)
    // and bottom (home indicator + lock-screen app row), used when the export is a lock-screen wallpaper.
    const SIZE_PRESETS = {
        fit: null,
        // Same iPhone ratio; the iOS 26 variant keeps extra top room for its larger lock-screen clock.
        'iphone-27': { w: 1290, h: 2796, label: 'iPhone (iOS 27)', topInset: 0.11, bottomInset: 0.10 },
        'iphone-26': { w: 1290, h: 2796, label: 'iPhone', topInset: 0.223, bottomInset: 0.10, compactHeader: true },
        'square': { w: 1080, h: 1080, label: 'Square', topInset: 0.025, bottomInset: 0.04 },
    };
    // Supersample factor applied to preset sizes for extra crispness (keeps within canvas limits).
    const PRESET_QUALITY = 1.6;
    // Render scale for "fit content" mode — high enough for 4K-class output.
    const FIT_SCALE = 4;

    // Render a schedule node to a canvas, either at its natural size (fit) or composited onto a
    // fixed-aspect canvas (phone / square) with the content scaled to contain and top-aligned.
    async function renderToCanvas(node, sizeKey) {
        const preset = SIZE_PRESETS[sizeKey];
        if (!preset) {
            return elementToCanvas(node, FIT_SCALE);
        }
        const g = exportGeometry(preset);
        const { finalW, finalH, sidePad, topPad, botReserve, contentW, contentH } = g;
        const rect = node.getBoundingClientRect();
        const logicalW = Math.max(1, rect.width);
        const logicalH = Math.max(1, rect.height);

        // Contain the schedule within the content area (between the top and bottom insets).
        let scale = contentW / logicalW;
        if (logicalH * scale > contentH) scale = contentH / logicalH;

        // Transparent content so the wallpaper shows through the gaps.
        const content = await elementToCanvas(node, scale, true);
        const wp = await loadWallpaper();
        const fc = document.createElement('canvas');
        fc.width = finalW;
        fc.height = finalH;
        const ctx = fc.getContext('2d');
        if (wp) {
            // Cover the canvas with the wallpaper, then darken it for legibility.
            const ir = wp.width / wp.height;
            const cr = finalW / finalH;
            let dw, dh;
            if (ir > cr) { dh = finalH; dw = dh * ir; } else { dw = finalW; dh = dw / ir; }
            ctx.drawImage(wp, (finalW - dw) / 2, (finalH - dh) / 2, dw, dh);
            ctx.fillStyle = 'rgba(0,0,0,0.58)';
            ctx.fillRect(0, 0, finalW, finalH);
            const grad = ctx.createLinearGradient(0, 0, 0, finalH);
            grad.addColorStop(0, 'rgba(0,0,0,0.55)');
            grad.addColorStop(0.18, 'rgba(0,0,0,0.15)');
            grad.addColorStop(1, 'rgba(0,0,0,0.35)');
            ctx.fillStyle = grad;
            ctx.fillRect(0, 0, finalW, finalH);
        } else {
            ctx.fillStyle = '#000000';
            ctx.fillRect(0, 0, finalW, finalH);
        }

        // Schedule content, top-aligned below the top inset.
        const dx = Math.round((finalW - content.width) / 2);
        ctx.drawImage(content, dx, topPad);

        // Consciencia logo in the bottom band (above the home-indicator / app-row area),
        // smaller, dimmed and with strongly feathered edges so it blends into the background.
        if ((preset.bottomInset || 0) >= 0.06) {
            const logo = await loadLogo();
            if (logo) {
                const appRowClear = finalH * 0.045;       // leave the very bottom clear of the logo
                const bandTop = finalH - botReserve;
                const bandBottom = finalH - appRowClear;
                const bandH = bandBottom - bandTop;
                let lw = finalW * 0.60;
                let lh = lw * (logo.height / logo.width);
                const maxLh = bandH * 0.9;
                if (lh > maxLh) { lh = maxLh; lw = lh * (logo.width / logo.height); }
                const lx = (finalW - lw) / 2;
                const ly = bandTop + (bandH - lh) / 2;
                drawFeatheredImage(ctx, logo, lx, ly, lw, lh, lw * 0.10, lh * 0.30, 0.5);
            }
        }
        return fc;
    }

    function triggerDownload(blob, filename) {
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = filename;
        document.body.appendChild(a);
        a.click();
        setTimeout(() => { URL.revokeObjectURL(url); a.remove(); }, 1000);
    }

    function downloadCanvasPNG(canvas, filename) {
        canvas.toBlob(blob => triggerDownload(blob, filename), 'image/png');
    }

    // Build a minimal single-page PDF embedding the canvas as a JPEG (DCTDecode) image.
    function buildPDF(jpegBytes, imgW, imgH) {
        const capW = imgW >= imgH ? 1000 : 700;
        const scale = capW / imgW;
        const pageW = imgW * scale;
        const pageH = imgH * scale;
        const enc = new TextEncoder();
        const parts = [];
        let len = 0;
        const offsets = [];
        const push = u8 => { parts.push(u8); len += u8.length; };
        const pushStr = s => push(enc.encode(s));
        const obj = (n, body) => { offsets[n] = len; pushStr(n + ' 0 obj\n' + body + '\nendobj\n'); };

        pushStr('%PDF-1.4\n%âãÏÓ\n');
        obj(1, '<< /Type /Catalog /Pages 2 0 R >>');
        obj(2, '<< /Type /Pages /Kids [3 0 R] /Count 1 >>');
        obj(3, '<< /Type /Page /Parent 2 0 R /MediaBox [0 0 ' + pageW.toFixed(2) + ' ' + pageH.toFixed(2) + ']' +
            ' /Resources << /XObject << /Im0 4 0 R >> >> /Contents 5 0 R >>');
        offsets[4] = len;
        pushStr('4 0 obj\n<< /Type /XObject /Subtype /Image /Width ' + imgW + ' /Height ' + imgH +
            ' /ColorSpace /DeviceRGB /BitsPerComponent 8 /Filter /DCTDecode /Length ' + jpegBytes.length + ' >>\nstream\n');
        push(jpegBytes);
        pushStr('\nendstream\nendobj\n');
        const content = 'q ' + pageW.toFixed(2) + ' 0 0 ' + pageH.toFixed(2) + ' 0 0 cm /Im0 Do Q';
        obj(5, '<< /Length ' + content.length + ' >>\nstream\n' + content + '\nendstream');

        const xrefOffset = len;
        let xref = 'xref\n0 6\n0000000000 65535 f \n';
        for (let i = 1; i <= 5; i++) {
            xref += String(offsets[i]).padStart(10, '0') + ' 00000 n \n';
        }
        pushStr(xref);
        pushStr('trailer\n<< /Size 6 /Root 1 0 R >>\nstartxref\n' + xrefOffset + '\n%%EOF');

        const out = new Uint8Array(len);
        let o = 0;
        for (const p of parts) { out.set(p, o); o += p.length; }
        return out;
    }

    function downloadCanvasPDF(canvas, filename) {
        const dataUrl = canvas.toDataURL('image/jpeg', 0.92);
        const bin = atob(dataUrl.split(',')[1]);
        const bytes = new Uint8Array(bin.length);
        for (let i = 0; i < bin.length; i++) bytes[i] = bin.charCodeAt(i);
        const pdf = buildPDF(bytes, canvas.width, canvas.height);
        triggerDownload(new Blob([pdf], { type: 'application/pdf' }), filename);
    }

    // Orchestrate a single export.
    const LAYOUT_RENDERERS = {
        agenda: renderVertical,
        columns: renderVerticalColumns,
        horizontal: renderHorizontal,
    };
    async function doExport(layout, format, size) {
        const { acts, missing } = buildScheduleData();
        if (acts.length === 0) {
            showToast('No acts selected to export!');
            return;
        }
        showToast('Rendering schedule…');
        const render = LAYOUT_RENDERERS[layout] || renderVertical;
        // When a fixed screen ratio is chosen, vertical layouts stretch to fill the drawable content
        // area (between the top/bottom insets), expressed in preset-logical pixels.
        const preset = SIZE_PRESETS[size];
        let opts = null;
        if (preset) {
            const g = exportGeometry(preset);
            opts = { w: g.contentW / PRESET_QUALITY, h: g.contentH / PRESET_QUALITY, compact: !!preset.compactHeader };
        }
        const node = render(acts, opts);
        // Offscreen positioning lives on a holder so it isn't serialized into the exported image.
        const holder = document.createElement('div');
        holder.style.cssText = 'position:fixed;left:-99999px;top:0;pointer-events:none;';
        holder.appendChild(node);
        document.body.appendChild(holder);
        try {
            await new Promise(r => setTimeout(r, 30));
            const canvas = await renderToCanvas(node, size);
            const day = new URLSearchParams(location.search).get('day') || 'schedule';
            const sizeTag = (size && size !== 'fit') ? '-' + size : '';
            const base = 'tomorrowland-' + day + '-' + layout + sizeTag;
            if (format === 'pdf') downloadCanvasPDF(canvas, base + '.pdf');
            else downloadCanvasPNG(canvas, base + '.png');
            showToast(missing ? ('Exported — ' + missing + ' act(s) missing details') : 'Schedule exported!');
        } catch (e) {
            console.error('Schedule export failed:', e);
            showToast('Export failed — see console');
        } finally {
            holder.remove();
        }
    }

    // Build (once) and toggle the export options modal.
    function openExportModal() {
        let modal = document.getElementById('tml-export-modal');
        if (!modal) {
            modal = document.createElement('div');
            modal.id = 'tml-export-modal';
            modal.className = 'tml-modal-overlay';
            const chip = (group, value, label, active) =>
                `<button class="tml-chip${active ? ' tml-chip-active' : ''}" data-group="${group}" data-value="${value}">${label}</button>`;
            modal.innerHTML = `
                <div class="tml-modal">
                    <div class="tml-modal-title">Export Schedule</div>

                    <div class="tml-modal-section">Layout</div>
                    <div class="tml-chip-row">
                        ${chip('layout', 'columns', 'Stage columns', true)}
                        ${chip('layout', 'agenda', 'Agenda', false)}
                        ${chip('layout', 'horizontal', 'Stage grid', false)}
                    </div>
                    <div class="tml-chip-desc" id="tml-layout-desc">Vertical · stages side by side, time ↓</div>

                    <div id="tml-size-section">
                        <div class="tml-modal-section">Size</div>
                        <div class="tml-chip-row">
                            ${chip('size', 'iphone-27', 'iPhone (iOS 27)', true)}
                            ${chip('size', 'iphone-26', 'iPhone', false)}
                            ${chip('size', 'fit', 'Fit content', false)}
                            ${chip('size', 'square', 'Square', false)}
                        </div>
                        <div class="tml-chip-desc" id="tml-size-desc">1290 × 2796 · iPhone, iOS 27 lock screen</div>
                    </div>

                    <div class="tml-modal-actions">
                        <button class="tml-btn" data-format="png">Download PNG</button>
                        <button class="tml-btn" data-format="pdf">Download PDF</button>
                    </div>
                    <button class="tml-btn tml-modal-close" id="tml-modal-close">Close</button>
                </div>`;
            document.body.appendChild(modal);

            const sel = { layout: 'columns', size: 'iphone-27' };
            const LAYOUT_DESC = {
                agenda: 'Vertical list · one act per row, time ↓',
                columns: 'Vertical · stages side by side, time ↓',
                horizontal: 'Horizontal · stages stacked, time →',
            };
            const SIZE_DESC = {
                fit: 'Image sized to the schedule · 4K-class resolution',
                'iphone-27': '1290 × 2796 · iPhone, iOS 27 lock screen',
                'iphone-26': '1290 × 2796 · iPhone, extra top room for the iOS 26 clock',
                'square': '1080 × 1080 · square',
            };

            modal.addEventListener('click', (e) => {
                if (e.target === modal) modal.classList.remove('tml-modal-visible');
            });
            modal.querySelector('#tml-modal-close').addEventListener('click', () => {
                modal.classList.remove('tml-modal-visible');
            });
            const sizeSection = modal.querySelector('#tml-size-section');
            const setActive = (group, value) => {
                modal.querySelectorAll('.tml-chip[data-group="' + group + '"]').forEach(o =>
                    o.classList.toggle('tml-chip-active', o.dataset.value === value));
            };
            // Phone/square ratios only apply to the vertical layouts; the horizontal grid is always "fit".
            const syncSizeVisibility = () => {
                if (sel.layout === 'horizontal') {
                    sel.size = 'fit';
                    setActive('size', 'fit');
                    modal.querySelector('#tml-size-desc').textContent = SIZE_DESC.fit;
                    sizeSection.style.display = 'none';
                } else {
                    sizeSection.style.display = '';
                }
            };
            modal.querySelectorAll('.tml-chip').forEach(c => {
                c.addEventListener('click', () => {
                    const group = c.dataset.group;
                    sel[group] = c.dataset.value;
                    setActive(group, c.dataset.value);
                    if (group === 'layout') {
                        modal.querySelector('#tml-layout-desc').textContent = LAYOUT_DESC[sel.layout];
                        syncSizeVisibility();
                    }
                    if (group === 'size') modal.querySelector('#tml-size-desc').textContent = SIZE_DESC[sel.size];
                });
            });
            modal.querySelectorAll('.tml-modal-actions button[data-format]').forEach(btn => {
                btn.addEventListener('click', () => {
                    modal.classList.remove('tml-modal-visible');
                    doExport(sel.layout, btn.dataset.format, sel.size);
                });
            });
        }
        modal.classList.add('tml-modal-visible');
    }

